proof_block:
// `SingleDelivery::receive(pre, post, pkt, ack, acks)` branches on
// `pkt.msg`; both r1- and r2-ensures share `pre_self_@` and `pkt@`, so
// once they are anchored on the *same* syntactic `pre_v`/`pkt_v` z3
// can line up the inner case-splits across the two runs.  The
// re-asserts below are all direct unfoldings of the existing ensures
// or of the open-spec bodies of `get_ack` / `get_abstracted_ack_set` /
// `new_single_message`; Verus will check each one.

let pre_v   = pre_self_@;
let pkt_v   = pkt@;
let post1_v = post1_self_@;
let post2_v = post2_self_@;
let ack1    = r1.get_ack()@;
let ack2    = r2.get_ack()@;
let acks1   = r1.get_abstracted_ack_set();
let acks2   = r2.get_abstracted_ack_set();

// (A) Re-anchor the two `SingleDelivery::receive(...)` ensures on the
//     shared (pre_v, pkt_v); this forces z3 to instantiate the
//     inner match-on-`pkt_v.msg` on the same scrutinee for both runs.
assert(SingleDelivery::receive(pre_v, post1_v, pkt_v, ack1, acks1));
assert(SingleDelivery::receive(pre_v, post2_v, pkt_v, ack2, acks2));

// (B) `ReceiveImplResult::get_abstracted_ack_set` is an open spec fn
//     whose value is determined by the variant tag — make the
//     correspondence visible so the variant-tag equality in
//     `det_receive_impl_equal` can be derived from the (aligned)
//     `acks` produced by `receive`.
assert(r1 is FreshPacket     ==> acks1 =~= set!{ack1});
assert(r1 is DuplicatePacket ==> acks1 =~= set!{ack1});
assert(r1 is AckOrInvalid    ==> acks1 =~= Set::<Packet>::empty());
assert(r2 is FreshPacket     ==> acks2 =~= set!{ack2});
assert(r2 is DuplicatePacket ==> acks2 =~= set!{ack2});
assert(r2 is AckOrInvalid    ==> acks2 =~= Set::<Packet>::empty());

// (C) Re-anchor the two `new_single_message` ensures on the shared
//     (pre_v, pkt_v); both runs' Fresh/Duplicate tags are now forced
//     to agree on the same boolean `SingleDelivery::new_single_message(pre_v, pkt_v)`.
assert(r1 is FreshPacket     ==>  SingleDelivery::new_single_message(pre_v, pkt_v));
assert(r1 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_v, pkt_v));
assert(r2 is FreshPacket     ==>  SingleDelivery::new_single_message(pre_v, pkt_v));
assert(r2 is DuplicatePacket ==> !SingleDelivery::new_single_message(pre_v, pkt_v));
